# 输入获取
operations = eval(input())


class Node:
    def __init__(self, val):
        self.val = val
        self.lc = None
        self.rc = None


# 算法入口
def getResult(operations):
    tree = [[Node(-1)]]

    for i in range(len(operations)):
        height, index = operations[i]

        if len(tree) <= height + 1:
            tree.append([])

        ch = Node(i)

        fa = tree[height][index]
        # 注意,tree用于记录树中加入成功的节点是第几行第几个创建的,对于加入的失败的不应该记录
        if not fa.lc or not fa.rc:
            tree[height + 1].append(ch)

        if not fa.lc:
            fa.lc = ch
        elif not fa.rc:
            fa.rc = ch

    ans = []
    queue = [tree[0][0]]

    while len(queue) > 0:
        node = queue.pop(0)

        if node is not None:
            ans.append(node.val)
            queue.append(node.lc)
            queue.append(node.rc)
        else:
            ans.append("null")

    while True:
        if ans[-1] == "null":
            ans.pop()
        else:
            break

    return ans


# 算法调用
res = str(getResult(operations))
print(res.replace("'", ""))
